const App: React.FC = () => {
  const getBasePath = () => {
    try {
      const hash = window.location.hash.replace('#', '') || '/';
      return hash.split('?')[0];
    } catch {
      return '/';
    }
  };

  const [currentPath, setCurrentPath] = useState(getBasePath());
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    const handleHashChange = () => {
      const fullHash = window.location.hash.replace('#', '') || '/';
      const [path] = fullHash.split('?');
      setCurrentPath(path);
    };
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  }, []);

  // Centraliza a busca do perfil para evitar duplicação de lógica
  const fetchAndSetUser = useCallback(async (email: string) => {
    try {
      const profile = await mockDb.login(email);
      if (profile) {
        setUser(profile);
      } else {
        // Se houver sessão mas o perfil falhar, não desloga imediatamente, tenta novamente ou limpa se for erro fatal
        console.warn("[Marclyn] Sessão ativa mas perfil não encontrado.");
      }
    } catch (e) {
      console.error("[Marclyn] Erro ao sincronizar perfil:", e);
    }
  }, []);

  useEffect(() => {
    let mounted = true;

    const initializeAuth = async () => {
      // 1. Tenta recuperar sessão existente imediatamente
      const { data: { session } } = await supabase.auth.getSession();

      if (mounted && session?.user?.email) {
        await fetchAndSetUser(session.user.email);
      }

      // 2. Escuta mudanças de estado (Login, Logout, Token Refresh)
      const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (!mounted) return;

        console.log(`[Marclyn Auth] Evento: ${event}`);

        if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED' || event === 'INITIAL_SESSION') {
          if (session?.user?.email) {
            await fetchAndSetUser(session.user.email);
          }
        } else if (event === 'SIGNED_OUT') {
          setUser(null);
        }

        // Finaliza o loading apenas após a primeira verificação completa
        setAuthLoading(false);
      });

      // Timeout de segurança: Se em 6s nada acontecer, libera a tela
      const timeoutId = setTimeout(() => {
        if (mounted && authLoading) {
          setAuthLoading(false);
        }
      }, 6000);

      return () => {
        mounted = false;
        subscription.unsubscribe();
        clearTimeout(timeoutId);
      };
    };

    initializeAuth();
  }, [fetchAndSetUser]);

  const navigate = (path: string) => {
    window.location.hash = path;
  };

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    navigate('/dashboard');
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = async () => {
    try {
      await supabase.auth.signOut();
      setUser(null);
      navigate('/');
    } catch (e) {
      setUser(null);
      navigate('/');
    }
  };

  const commonProps = { onNavigate: navigate, showToast };

  const renderContent = () => {
    if (currentPath.startsWith('/teleconsulta/')) {
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        return <TeleconsultationRoom user={user} {...commonProps} />;
    }

    if (currentPath.startsWith('/professional/')) {
        return <ProfessionalPublicProfile user={user} {...commonProps} />;
    }

    switch (currentPath) {
      case '/': return <Home user={user} {...commonProps} />;
      case '/search': return <SearchPage user={user} {...commonProps} />;
      case '/login': return <Login onLogin={handleLogin} {...commonProps} />;
      case '/register-patient': return <RegisterPatient onLogin={handleLogin} {...commonProps} />;
      case '/register-partner': return <RegisterPartner {...commonProps} />;
      case '/dashboard':
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        if (user.role === 'admin') return <AdminDashboard user={user} onNavigate={navigate} />;
        if (user.role === 'clinic' || user.role === 'professional') return <ClinicDashboard user={user} onNavigate={navigate} />;
        return <PatientDashboard user={user} showToast={showToast} onNavigate={navigate} />;
      case '/admin/approvals':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminApprovals onBack={() => navigate('/dashboard')} showToast={showToast} />;
      case '/admin/subscriptions':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminSubscriptions onNavigate={navigate} showToast={showToast} />;
      case '/admin/logs':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminLogs onNavigate={navigate} />;
      case '/admin/settings':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminSystemSettings onNavigate={navigate} showToast={showToast} />;
      case '/profile':
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        return <ProfilePage user={user} {...commonProps} />;
      case '/documents':
         if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
         return <DocumentsPage user={user} onNavigate={navigate} />;
      case '/consultation':
         if (!user || (user.role !== 'clinic' && user.role !== 'professional')) return <Home user={user} {...commonProps} />;
         return <ConsultationPage user={user} {...commonProps} />;
      case '/schedule':
         if (!user || (user.role !== 'clinic' && user.role !== 'professional')) return <Home user={user} {...commonProps} />;
         return <SchedulePage user={user} {...commonProps} />;
      case '/settings': return <SettingsPage onNavigate={navigate} />;
      default: return <Home user={user} {...commonProps} />;
    }
  };

  if (authLoading) {
    return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6">
            <div className="relative">
                <div className="w-16 h-16 border-4 border-teal-500/20 border-t-teal-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                    <RefreshCw className="text-teal-500 opacity-40" size={20} />
                </div>
            </div>
            <div className="mt-6 text-center">
                <p className="text-teal-400 font-black uppercase text-[10px] tracking-widest mb-1 animate-pulse">Autenticando Marclyn</p>
                <p className="text-slate-500 text-[8px] uppercase font-bold tracking-widest">Sessão Segura</p>
            </div>
        </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} onNavigate={navigate}>
      {renderContent()}

      {toast && (
        <div className={`fixed top-6 right-6 z-[110] p-4 rounded-lg shadow-2xl flex items-center gap-3 animate-slideIn transition-all duration-300 max-w-sm ${toast.type === 'success' ? 'bg-slate-900 text-white' : 'bg-red-600 text-white'}`}>
          <div className={`${toast.type === 'success' ? 'text-teal-400' : 'text-white'}`}>
            {toast.type === 'success' ? <CheckCircle size={24} /> : <AlertTriangle size={24} />}
          </div>
          <div>
            <p className="font-bold text-sm">{toast.type === 'success' ? 'Sucesso' : 'Erro'}</p>
            <p className="text-sm opacity-90">{toast.message}</p>
          </div>
          <button onClick={() => setToast(null)} className="ml-2 hover:opacity-75">
            <X size={16} />
          </button>
        </div>
      )}
    </Layout>
  );
};

export default App;

