/**
 * MARCLYN RESILIENCE ENGINE
 * Implementa Retry Exponencial e Timeout Inteligente
 */
const executeWithRetry = async (operation: () => Promise<any>, maxRetries = 3, timeoutMs = 8000): Promise<any> => {
    let lastError: any;

    for (let attempt = 0; attempt < maxRetries; attempt++) {
        try {
            // Cria uma promessa que rejeita após o timeout
            const timeoutPromise = new Promise((_, reject) => 
                setTimeout(() => reject(new Error("TIMEOUT_CONNECTION")), timeoutMs)
            );

            // Tenta a operação com timeout
            return await Promise.race([operation(), timeoutPromise]);
        } catch (error: any) {
            lastError = error;
            const isTimeout = error.message === "TIMEOUT_CONNECTION";

            console.warn(`[Marclyn Retry] Tentativa ${attempt + 1}/${maxRetries} falhou:`, error.message);

            // Se for o último erro, não espera
            if (attempt < maxRetries - 1) {
                // Backoff exponencial: 500ms, 1000ms, 2000ms...
                const waitTime = Math.pow(2, attempt) * 500;
                await new Promise(res => setTimeout(res, waitTime));
            }
        }
    }
    throw lastError;
};

