  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    try {
        const data = await executeWithRetry(() => 
            supabase
                .from('profiles')
                .select('*')
                .eq('email', email)
                .maybeSingle()
        );

        if (data) return mapProfileToUser(data);
    } catch (e) {
        console.error("[Marclyn DB] Falha crítica ao recuperar perfil após retentativas:", e);
        throw e; // Propaga para o App.tsx tratar o fallback
    }
    return null;
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    try {
        const { data, error } = await executeWithRetry(() => supabase.auth.signInWithPassword({ email, password }));
        if (error) throw error;

        if (data.user) {
            const profile = await executeWithRetry(() => supabase.from('profiles')
                .select('*')
                .eq('id', data.user.id)
                .maybeSingle());

            if (profile) return mapProfileToUser(profile);
        }
