        };
    } catch (e) {
        return null;
    }
  },

  getStats: async () => {
    try {
        const { count: users } = await executeWithRetry(() => supabase.from('profiles').select('*', { count: 'exact', head: true }));
        const { count: pending } = await executeWithRetry(() => supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending'));
        const { count: apps } = await executeWithRetry(() => supabase.from('appointments').select('*', { count: 'exact', head: true }));
        return { users: users || 0, clinics: 0, appointments: apps || 0, records: 0, pendingUsers: pending || 0 };
    } catch (e) {
        return { users: 0, clinics: 0, appointments: 0, records: 0, pendingUsers: 0 };
    }
  },

  getPendingUsers: async (): Promise<User[]> => {
    try {
        const data = await executeWithRetry(() => supabase.from('profiles').select('*').eq('status', 'pending'));
        return (data || []).map(mapProfileToUser);
    } catch (e) {
        return [];
    }
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    try {
        const data = await executeWithRetry(() => supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }));
        return (data || []).map(n => ({ id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any }));
    } catch (e) {
        return [];
    }
  },

  toggleFavorite: async (uid: string, cid: string) => {
    try {
        const p = await executeWithRetry(() => supabase.from('profiles').select('favorites').eq('id', uid).single());
        let favs = p?.favorites || [];
        favs = favs.includes(cid) ? favs.filter((id: any) => id !== cid) : [...favs, cid];
        const data = await executeWithRetry(() => supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single());
        return mapProfileToUser(data);
    } catch (e) {
        return null;
    }
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    let favIds: string[] = [];
    try {
      const response = await executeWithRetry(() => supabase.from('profiles').select('favorites').eq('id', uid).maybeSingle());
      favIds = response?.favorites || [];
    } catch (e) {}

    if (favIds.length === 0) return [];

    try {
        const data = await executeWithRetry(() => supabase.from('profiles')
            .select('*')
            .in('id', favIds));

        if (data) {
            return data.map(p => ({
                id: p.id,
                name: p.name,
                specialty: p.specialty || 'Saúde',
                location: 'Salvador-BA',
                neighborhood: p.address || 'Centro',
                price: p.price || 'A consultar',
                imageUrl: p.avatar_url,
                rating: p.rating || 5.0,
                reviewCount: p.review_count || 0,
                testimonial: p.bio,
                availableServices: p.available_services || []
            }));
        }
    } catch (e) {}
    return [];
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    // Fix: access up.avatarUrl instead of non-existent up.avatar_url
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }

    const data = await executeWithRetry(() => supabase.from('profiles').update({
      name: up.name, phone: up.phone, address: up.address, bio: up.bio, price: up.price,
      operating_hours: up.operatingHours, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, medical_history: up.medicalHistory,
      avatar_url: avatarUrl
    }).eq('id', uid).select().single());
    return mapProfileToUser(data);
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    try {
        const data = await executeWithRetry(() => supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).order('created_at', { ascending: false }));
        return (data || []).map(mapProfileToUser);
    } catch (e) {
