  },

  createTimeSlot: async (cid: string, date: string, time: string) => {
    await executeWithRetry(() => supabase.from('time_slots').insert({ clinic_id: cid, date, time }));
  },
  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]) => {
    const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time }));
    await executeWithRetry(() => supabase.from('time_slots').insert(payload));
    return slots.length;
  },
  deleteTimeSlot: async (id: string) => {
    await executeWithRetry(() => supabase.from('time_slots').delete().eq('id', id));
  },
  submitReview: async (clinicId: string, rating: number, comment: string) => {
    const data = await executeWithRetry(() => supabase.from('profiles').select('rating, review_count').eq('id', clinicId).single());
    if (!data) return;
    const p = data as any;
    const currentRating = p.rating || 5.0;
    const currentCount = p.review_count || 0;
    const newCount = currentCount + 1;
    const newRating = ((currentRating * currentCount) + rating) / newCount;
    await executeWithRetry(() => supabase.from('profiles').update({ 
      rating: newRating, 
      review_count: newCount,
      bio: comment
    }).eq('id', clinicId));
  },
  getClinicFinancials: async (cid: string) => {
    try {
        const data = await executeWithRetry(() => supabase.from('appointments').select('*').eq('clinic_id', cid).eq('status', 'done'));
        const total = (data || []).length * 150;
        return { totalRevenue: total, chartData: [{ day: 'HOJE', value: total }] };
    } catch (e) {
        return { totalRevenue: 0, chartData: [] };
    }
  },
  markNotificationAsRead: async (id: string) => {
    await executeWithRetry(() => supabase.from('notifications').update({ read: true }).eq('id', id));
  }
};
